   337→    "Capture a screenshot (full screen, region, or window). Default to full screen if no preference. This will also provide information about the user's screen in order to correctly position mouse clicks and keyboard inputs.",
   338→  parameters: z.object({
   339→    mode: z
   340→      .enum(["full", "region", "window"])
   341→      .default("full")
