   372→      const filePath = path.join(
   373→        os.tmpdir(),
   374→        `mcp_screenshot_${Date.now()}.png`
   375→      );
   376→
   377→      // Perform the OS-level screencapture
   378→      if (mode === "full") {
   379→        child_process.execSync(`screencapture -x -D1 "${filePath}"`);
   380→      } else if (mode === "region") {
   381→        if (
   382→          regionX === undefined ||
   383→          regionY === undefined ||
   384→          regionWidth === undefined ||
   385→          regionHeight === undefined
   386→        ) {
