   410→            "Could not determine target window ID for screenshot."
   411→          );
   412→        child_process.execSync(`screencapture -x -l${targetId} "${filePath}"`);
   413→      }
   414→
   415→      if (!require("fs").existsSync(filePath)) {
   416→        throw new Error(`Screenshot file was not created at ${filePath}`);
   417→      }
   418→
