   533→      // Another fallback using AppleScript
   534→      try {
   535→        const output = child_process
   536→          .execSync(
   537→            `osascript -e 'tell application "System Events" to get name of first application process whose frontmost is true'`
   538→          )
   539→          .toString()
   540→          .trim();
   541→        return `Active window: "${output}"`;
   542→      } catch (e2) {
