   551→// Tool 16: Window Control
   552→server.addTool({
   553→  name: "windowControl",
   554→  description: "Control a window (focus, move, resize, minimize, restore).",
   555→  parameters: z.object({
   556→    action: z
   557→      .enum(["focus", "move", "resize", "minimize", "restore"])
   558→      .describe("Action to perform"),
   559→    windowTitle: z
   560→      .string()
   561→      .optional()
   562→      .describe("Window title to target (uses active window if not provided)"),
   563→    x: z.number().optional().describe("X coordinate for move action"),
   564→    y: z.number().optional().describe("Y coordinate for move action"),
   565→    width: z.number().optional().describe("Width for resize action"),
   566→    height: z.number().optional().describe("Height for resize action"),
   567→  }),
   568→  execute: async ({ action, windowTitle, x, y, width, height }) => {
   569→    if (!nutjsAvailable) {
   570→      // Limited functionality without nutjs
   571→      if (action === "focus" && windowTitle) {
