   775→          await keyboard.releaseKey(cmdKey, Key.S);
   776→          return "Executed save command";
   777→
   778→        case "quit":
   779→          if (isMac) {
   780→            await keyboard.pressKey(cmdKey, Key.Q);
   781→            await keyboard.releaseKey(cmdKey, Key.Q);
   782→          } else {
   783→            await keyboard.pressKey(Key.LeftAlt, Key.F4);
   784→            await keyboard.releaseKey(Key.LeftAlt, Key.F4);
   785→          }
   786→          return "Executed quit command";
   787→
   788→        case "minimize":
   789→          if (isMac) {
   790→            await keyboard.pressKey(cmdKey, Key.M);
   791→            await keyboard.releaseKey(cmdKey, Key.M);
   792→          } else {
   793→            await keyboard.pressKey(Key.LeftSuper, Key.Down);
   794→            await keyboard.releaseKey(Key.LeftSuper, Key.Down);
   795→          }
